import{_ as t,o as r,c as a,ai as e}from"./chunks/framework.DMjte4z8.js";const q=JSON.parse('{"title":"地图性能优化指南","description":"","frontmatter":{"title":"地图性能优化指南","category":"advanced","updated":"2026-05-21T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.86,"discovered_via":"manual","sources":["https://www.hiveworkshop.com/threads/how-to-improve-the-performance-reduce-lags-of-a-map-with-many-units-fighting-and-spawned.332106/","https://www.hiveworkshop.com/threads/general-questions-about-trigger-optimizing-and-performance.346180/","https://www.reddit.com/r/warcraft3/comments/o45ryw/how_to_stop_map_lag/","https://www.thehelper.net/threads/increasing-warcraft-iii-performance-vista.94017/"]},"headers":[],"relativePath":"advanced/地图性能优化指南.md","filePath":"advanced/地图性能优化指南.md","lastUpdated":1779353774000}'),l={name:"advanced/地图性能优化指南.md"};function i(n,o,s,u,g,p){return r(),a("div",null,[...o[0]||(o[0]=[e('<h1 id="地图性能优化指南" tabindex="-1">地图性能优化指南 <a class="header-anchor" href="#地图性能优化指南" aria-label="Permalink to “地图性能优化指南”">​</a></h1><h2 id="什么是地图性能-为什么优化很重要" tabindex="-1">什么是地图性能？为什么优化很重要？ <a class="header-anchor" href="#什么是地图性能-为什么优化很重要" aria-label="Permalink to “什么是地图性能？为什么优化很重要？”">​</a></h2><p>在制作魔兽争霸3地图时，&quot;性能&quot;指的是你的地图在游戏中运行的流畅程度。简单来说，就是游戏会不会卡顿、延迟或者变慢。优化性能，就是让你的地图在各种电脑配置上都能流畅运行，让玩家有良好的游戏体验[^1]。</p><p>想象一下：你花了一周时间精心设计了一场史诗级Boss战，结果玩家一进去就发现卡得根本没法玩——这就是性能问题导致的严重后果。所以性能优化不是&quot;锦上添花&quot;，而是地图制作的&quot;必修课&quot;。</p><h3 id="性能问题的常见表现" tabindex="-1">性能问题的常见表现 <a class="header-anchor" href="#性能问题的常见表现" aria-label="Permalink to “性能问题的常见表现”">​</a></h3><blockquote><p><strong>💡 新手提示</strong>：有时候&quot;卡&quot;不一定是性能问题，也可能是网络延迟。先确认是在单人模式还是多人模式下出现的。</p></blockquote><p>当你的地图出现以下情况时，往往意味着存在性能问题：</p><ol><li><strong>画面帧率下降</strong> — 游戏画面不再流畅，像&quot;幻灯片&quot;一样断断续续[^3]</li><li><strong>单位响应迟钝</strong> — 移动、攻击指令有明显的延迟感</li><li><strong>技能释放卡顿</strong> — 释放技能时需要等待才能生效</li><li><strong>战斗时特别明显</strong> — 单位越多，卡顿越严重[^1]</li></ol><h3 id="为什么你的地图会变卡" tabindex="-1">为什么你的地图会变卡？ <a class="header-anchor" href="#为什么你的地图会变卡" aria-label="Permalink to “为什么你的地图会变卡？”">​</a></h3><blockquote><p><strong>⚠️ 常见错误</strong>：新手常以为&quot;地图小就一定不卡&quot;，其实即使是小地图，如果触发器写得不好（比如无限循环、重复执行），也会造成严重卡顿。</p></blockquote><p>你的地图变卡主要有以下几个原因：</p><ol><li><strong>单位数量过多</strong> — 地图上同时存在大量单位时，电脑需要计算每个单位的位置、状态、寻路等，负担会急剧增加[^1]</li><li><strong>触发器逻辑复杂</strong> — 如果触发器编写不当（比如每帧都检查大量条件），会消耗大量系统资源[^2]</li><li><strong>不断创建和销毁单位</strong> — 频繁生成怪物、召唤物等，会造成内存和CPU的额外负担</li><li><strong>同时播放太多特效</strong> — 技能特效、爆炸动画等都会影响帧率</li></ol><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>通过本节内容，你应该理解了：</p><ul><li>地图性能 = 游戏运行的流畅程度</li><li>卡顿会严重影响玩家体验，可能导致没人愿意玩你的地图</li><li>性能问题主要来源于单位数量、触发器逻辑和特效过多</li></ul><p>在接下来的章节中，我们将学习如何诊断和解决这些性能问题！</p><h2 id="触发器-trigger-优化技巧" tabindex="-1">触发器（Trigger）优化技巧 <a class="header-anchor" href="#触发器-trigger-优化技巧" aria-label="Permalink to “触发器（Trigger）优化技巧”">​</a></h2><p>触发器是让地图&quot;动起来&quot;的核心工具，但写不好会导致游戏卡顿甚至崩溃。本节教你三个实用技巧，让你的地图运行更流畅！</p><h3 id="常见触发器泄漏-leak-及解决方法" tabindex="-1">常见触发器泄漏（Leak）及解决方法 <a class="header-anchor" href="#常见触发器泄漏-leak-及解决方法" aria-label="Permalink to “常见触发器泄漏（Leak）及解决方法”">​</a></h3><p>触发器泄漏（Leak）是指触发器在执行过程中创建了一些&quot;临时数据&quot;（比如位置点、单位组），但没有及时清理它们。这些数据会一直占用内存，导致游戏越来越卡。</p><p><strong>操作步骤</strong></p><ol><li><strong>打开触发器编辑器</strong> — 在World Editor左侧菜单点击&quot;触发器&quot;图标[^1]</li><li><strong>找到可能产生泄漏的触发器</strong> — 常见会产生泄漏的操作包括： <ul><li>创建&quot;位置点&quot;（Point）后没有删除它</li><li>创建&quot;单位组&quot;（Unit Group）后没有清空它</li><li>使用&quot;选取区域内单位&quot;但没有清理选取结果</li></ul></li><li><strong>在操作末尾添加清理语句</strong> — 每次创建位置点或单位组后，在触发器最后添加对应的&quot;删除&quot;操作： <ul><li>位置点用&quot;删除位置&quot;</li><li>单位组用&quot;删除单位组&quot;[^2]</li></ul></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手只在触发器开头创建变量，却在结束时忘记删除它们。记住：<strong>有创建就必须有删除</strong>！</p></blockquote><h3 id="如何减少触发器执行次数" tabindex="-1">如何减少触发器执行次数 <a class="header-anchor" href="#如何减少触发器执行次数" aria-label="Permalink to “如何减少触发器执行次数”">​</a></h3><p>触发器执行次数太多会让游戏变卡。减少执行次数最有效的方法是使用<strong>条件（Condition）</strong>来过滤不必要的执行。</p><p><strong>操作步骤</strong></p><ol><li><strong>找到重复执行的触发器</strong> — 比如&quot;单位死亡&quot;这类事件可能被频繁触发</li><li><strong>在触发器中添加条件判断</strong> — 点击触发器编辑器中的&quot;条件&quot;按钮，添加筛选逻辑[^2]</li><li><strong>使用布尔变量控制</strong> — 对于需要临时阻止触发器执行的情况，创建&quot;开关&quot;变量： <ul><li>需要关闭时设置为&quot;关&quot;</li><li>需要开启时设置为&quot;开&quot;</li><li>在触发器条件中检查这个开关状态</li></ul></li></ol><blockquote><p><strong>💡 新手提示</strong>：把条件检查想象成&quot;安检门&quot;——不符合条件的人和事件直接被拦住，不会进入触发器内部执行。</p></blockquote><h3 id="计时器-timer-和等待-wait-的使用注意" tabindex="-1">计时器（Timer）和等待（Wait）的使用注意 <a class="header-anchor" href="#计时器-timer-和等待-wait-的使用注意" aria-label="Permalink to “计时器（Timer）和等待（Wait）的使用注意”">​</a></h3><p><strong>计时器（Timer）</strong>和<strong>等待（Wait）</strong>都用于延时执行，但性能差异很大。</p><p><strong>为什么Wait要少用？</strong></p><ul><li>&quot;等待&quot;会暂停整个触发器线程</li><li>如果有大量&quot;等待&quot;同时存在，会严重占用游戏资源</li><li>游戏卡顿时，&quot;等待&quot;的时间可能不准确[^2]</li></ul><p><strong>操作步骤</strong></p><ol><li><strong>优先使用计时器替代Wait</strong> — 创建计时器时点击&quot;新建计时器&quot;[^1]</li><li><strong>设置计时器到期事件</strong> — 选中计时器，点击&quot;到期事件&quot;添加</li><li><strong>在计时器到期时执行操作</strong> — 在对应触发器中写入需要在延时后执行的代码</li><li><strong>使用完毕后销毁计时器</strong> — 在操作末尾添加&quot;销毁计时器&quot;防止内存泄漏[^2]</li></ol><blockquote><p><strong>💡 新手提示</strong>：计时器就像&quot;闹钟&quot;——设置好之后可以同时运行多个而不互相干扰；等待（Wait）则像&quot;原地不动等人&quot;——效率低且容易出问题。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成以上三个技巧的学习后，你应该能够：</p><ul><li>✅ 识别并修复基本的触发器泄漏问题</li><li>✅ 使用条件过滤减少不必要的触发器执行</li><li>✅ 用计时器替代等待（Wait）来优化延时逻辑</li></ul><p>坚持使用这些习惯，你的地图在战斗激烈时也能保持流畅！</p><h2 id="单位与对象池管理" tabindex="-1">单位与对象池管理 <a class="header-anchor" href="#单位与对象池管理" aria-label="Permalink to “单位与对象池管理”">​</a></h2><p>本节将教你如何在地图中合理管理单位数量，以及如何使用&quot;对象池&quot;技术来减少卡顿。学完以后，你的地图在战斗激烈时也能保持流畅！</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：了解地图单位的性能影响</strong> — 在魔兽争霸III中，单位数量直接影响游戏流畅度。当地图上同时存在超过50个单位时，游戏可能会开始出现卡顿[^1]。单位越多，服务器需要计算的碰撞、寻路和生命值更新就越多[^2]。</p></li><li><p><strong>第二步：创建对象池变量</strong> — 在触发器编辑器中，点击&quot;变量&quot;新建一个数组变量，命名为<code>单位池</code>。这个变量将存储预先创建好的单位，而非临时生成[^1]。</p></li><li><p><strong>第三步：预创建单位</strong> — 在地图初始化触发器中，使用&quot;创建单位&quot;动作，把需要用到的单位（比如小怪、士兵）提前生成5-10个，放入<code>单位池</code>数组中。设置这些单位为&quot;隐藏&quot;状态，玩家看不到它们。</p></li><li><p><strong>第四步：从对象池取用单位</strong> — 当你需要生成敌人时，不要用&quot;创建单位&quot;，而是：</p><ul><li>从数组中取出一个隐藏单位</li><li>用&quot;显示单位&quot;并设置位置</li><li>用&quot;设置单位生命值&quot;重置状态</li></ul></li><li><p><strong>第五步：归还对象池</strong> — 战斗结束后，不要&quot;删除单位&quot;，而是：</p><ul><li>将单位移到地图外的隐藏区域</li><li>使用&quot;隐藏单位&quot;动作</li><li>把单位重新放回数组备用</li></ul></li></ol><blockquote><p><strong>💡 新手提示</strong>：对象池的大小很重要！如果你的波次最多需要20个敌人，就创建25个预制单位留些余量，但不要创建100个却只用20个——闲置单位同样会消耗性能。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手喜欢在触发器里频繁使用&quot;创建单位&quot;和&quot;删除单位&quot;。这样会导致游戏内存不断分配和释放，造成严重卡顿。解决方法是无论如何都改用对象池管理[^3]。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你的地图应该能在单位较多时依然保持流畅。关键记住：<strong>预先创建、用完隐藏、重复利用</strong>。这样即使有大量单位战斗，也不会因为不断创建删除而卡顿[^1]！</p><h2 id="jass脚本基础优化" tabindex="-1">JASS脚本基础优化 <a class="header-anchor" href="#jass脚本基础优化" aria-label="Permalink to “JASS脚本基础优化”">​</a></h2><p>本节将教你JASS脚本中两种函数的选择原则，以及如何通过简化重复代码来提升地图运行效率。学完本节后，你的地图在单位较多时也能保持流畅。</p><h3 id="原生函数-vs-bj函数的选择" tabindex="-1">原生函数 vs BJ函数的选择 <a class="header-anchor" href="#原生函数-vs-bj函数的选择" aria-label="Permalink to “原生函数 vs BJ函数的选择”">​</a></h3><p>JASS脚本中存在两种函数：<strong>原生函数（Native）</strong> 是魔兽引擎直接提供的底层函数，效率高但参数较多；<strong>BJ函数</strong> 是暴雪封装的高层包装函数，使用简单但会额外执行一些检查，效率略低。[^2]</p><p><strong>优化建议</strong>：在频繁执行的触发器中，优先使用原生函数替代BJ函数。例如，<code>GetUnitsInRangeOfLocAll</code> 是BJ函数，而使用原生循环遍历单位会更高效。[^1]</p><h3 id="简化重复代码提高效率" tabindex="-1">简化重复代码提高效率 <a class="header-anchor" href="#简化重复代码提高效率" aria-label="Permalink to “简化重复代码提高效率”">​</a></h3><p><strong>操作步骤</strong>：</p><ol><li><p><strong>打开触发编辑器</strong> — 在World Editor中按F4打开触发器编辑器，双击你要优化的触发器[^2]</p></li><li><p><strong>转换为自定义脚本</strong> — 在触发器动作中右键选择&quot;转换为自定义脚本&quot;，这样可以直接编写JASS代码</p></li><li><p><strong>用循环替代重复调用</strong> — 将多次相同的函数调用合并为一个循环，例如不要写10次创建单位，而是用循环创建10次[^1]</p></li><li><p><strong>减少不必要的作用域查找</strong> — 将常用函数结果保存到变量中，避免每帧重复计算单位数量[^3]</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你不确定某个BJ函数是否有更快的原生替代方案，可以在社区搜索&quot;JASS函数对照表&quot;，很多前辈已经整理好了对应关系。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易把所有触发器都写成BJ函数风格。虽然BJ函数更易读，但在大量单位同时行动时会导致明显卡顿。建议对&quot;每X秒执行&quot;这类高频触发器优先优化。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上优化后，你的触发器执行效率会明显提升。特别是在有大量单位战斗或刷怪的地图中，优化后的脚本可以让游戏在15分钟后依然保持流畅而非卡顿。</p><h2 id="地图设置与编辑器配置" tabindex="-1">地图设置与编辑器配置 <a class="header-anchor" href="#地图设置与编辑器配置" aria-label="Permalink to “地图设置与编辑器配置”">​</a></h2><p>本节将教你如何在魔兽争霸III编辑器（World Editor）中配置地图的基础设置，包括路径网格精度和地图大小，以及视野和战争迷雾的优化方案。学完本节后，你的地图将拥有更合理的性能基础，避免因设置不当导致的卡顿问题。</p><h3 id="路径网格与地图大小设置" tabindex="-1">路径网格与地图大小设置 <a class="header-anchor" href="#路径网格与地图大小设置" aria-label="Permalink to “路径网格与地图大小设置”">​</a></h3><ol><li><p><strong>第一步：打开场景管理器</strong> — 在编辑器顶部菜单栏点击&quot;场景&quot;（Scenario）选项，在下拉菜单中选择&quot;地图&quot;（Map）[^1]。这会打开地图属性对话框。</p></li><li><p><strong>第二步：调整路径网格大小</strong> — 在地图属性中找到&quot;路径网格大小&quot;（Pathing Map Size）设置。这里需要理解一个概念：路径网格是用来告诉电脑&quot;哪里可以走、哪里不能走&quot;的隐形格子。格子越小，精度越高，但电脑需要计算的格子数量就越多。建议新手选择&quot;普通&quot;（Medium）而非&quot;精细&quot;（Fine）设置，除非你的地图有非常精细的寻路需求[^2]。</p></li><li><p><strong>第三步：设置地图尺寸</strong> — 在同一对话框中找到&quot;地图大小&quot;（Map Size）选项。魔兽III支持从小图（Small）到史诗巨图（Epic）等多种尺寸。有玩家反馈，史诗大小的地图在游戏进行到15分钟后容易出现明显卡顿[^3]。如果你的地图不需要很大的冒险空间，建议选择&quot;大&quot;（Large）而非&quot;史诗&quot;（Epic），这样能显著减轻电脑负担。</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手认为地图越大越专业，实际上史诗巨图会成倍增加内存占用和计算量。如果你的RPG地图只需要一个城镇和周边区域，选择&quot;大&quot;尺寸就足够了。</p></blockquote><h3 id="视野与战争迷雾配置建议" tabindex="-1">视野与战争迷雾配置建议 <a class="header-anchor" href="#视野与战争迷雾配置建议" aria-label="Permalink to “视野与战争迷雾配置建议”">​</a></h3><ol><li><p><strong>第一步：进入高级设置</strong> — 在地图属性对话框中，点击&quot;高级&quot;（Advanced）标签页。这里集中了影响游戏性能的隐藏选项。</p></li><li><p><strong>第二步：调整视野范围</strong> — 找到&quot;视野范围&quot;（Visibility）设置。每隔玩家的&quot;视野&quot;就是他能看到的区域大小。如果设置过高，电脑需要同时渲染更多单位的视野范围，会导致战斗激烈时卡顿。建议保持默认值，除非你制作的是需要超远视野的特定玩法地图。</p></li><li><p><strong>第三步：配置战争迷雾</strong> — 战争迷雾（Fog of War）是指地图上玩家未曾探索的区域会变暗的效果。这个功能很酷，但会消耗额外性能。如果你追求极致流畅，可以将战争迷雾设置为&quot;隐藏未探索区域&quot;而非&quot;显示地形但隐藏单位&quot;；如果你想让地图更有探索乐趣，保持默认设置即可[^2]。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：如果你不确定某个设置是否影响性能，可以先制作两版地图分别测试。一版用默认设置，一版按上述建议优化，对比运行效果。实践出真知！</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你的地图将拥有一个平衡性能和游戏体验的基础配置。记住：路径网格用&quot;普通&quot;、地图大小够用就好、视野保持默认、战争迷雾按需调整。这些设置虽然看起来简单，但往往是新手地图卡顿的根源所在。现在你可以打开编辑器试着调整这些选项，然后测试一下优化效果！</p><h2 id="性能测试与调试工具" tabindex="-1">性能测试与调试工具 <a class="header-anchor" href="#性能测试与调试工具" aria-label="Permalink to “性能测试与调试工具”">​</a></h2><p>本节将教你如何使用魔兽争霸3编辑器的内置工具来<strong>检测地图的性能问题</strong>，以及一些<strong>实用的调试技巧</strong>。学完本节后，你将能够定位哪些触发器导致了卡顿，并学会基本的优化验证方法。</p><h3 id="如何检测触发器执行效率" tabindex="-1">如何检测触发器执行效率 <a class="header-anchor" href="#如何检测触发器执行效率" aria-label="Permalink to “如何检测触发器执行效率”">​</a></h3><ol><li><p><strong>第一步：打开触发器编辑器</strong> — 在世界编辑器中，点击顶部菜单的&quot;触发器&quot;（Trigger）按钮，打开触发器编辑器窗口[^1]</p></li><li><p><strong>第二步：创建测试触发器</strong> — 新建一个空的测试触发器，命名为&quot;性能测试&quot;。这个触发器的作用是帮我们测量其他触发器的执行时间</p></li><li><p><strong>第三步：添加计时显示</strong> — 在你的目标触发器开头插入一个&quot;显示调试信息&quot;动作（Display Debug Message），打印一个带时间的标记，比如&quot;触发器A开始&quot;。在触发器末尾也打印一条，记录结束时间[^2]</p></li><li><p><strong>第四步：运行测试地图</strong> — 按F10或点击&quot;测试&quot;按钮启动游戏。游玩几分钟后，按ESC打开控制台，观察打印的调试信息。如果两条信息之间间隔过长，说明这个触发器需要优化[^3]</p></li><li><p><strong>第五步：逐一排除法</strong> — 如果地图很复杂，可以临时&quot;禁用触发器&quot;（Disable Trigger），然后重新测试。对比启用和禁用状态下帧率（FPS）的变化，快速定位问题触发器</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记关闭调试信息就直接发布地图，导致所有玩家都能看到一堆乱码文字。<strong>解决方法</strong>：发布前把&quot;显示调试信息&quot;动作全部删除，或改为只在特定条件下执行（比如仅当你自己的玩家ID为1时才显示）。</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：在触发器编辑器中，按住鼠标左键拖动可以同时选中多个动作，右键选择&quot;折叠&quot;可以暂时隐藏不重要的触发器，让界面更清爽。</p></blockquote><h3 id="实用调试技巧与工具推荐" tabindex="-1">实用调试技巧与工具推荐 <a class="header-anchor" href="#实用调试技巧与工具推荐" aria-label="Permalink to “实用调试技巧与工具推荐”">​</a></h3><ol><li><p><strong>使用计时器变量</strong> — 创建一个&quot;计时器&quot;（Timer）类型的变量。在触发器开始时用&quot;启动计时器&quot;动作，结束时用&quot;暂停计时器&quot;并获取剩余时间，这样可以精确测量执行耗时[^2]</p></li><li><p><strong>监控单位数量</strong> — 创建一个每5秒执行的触发器，使用&quot;获取区域内单位数量&quot;动作，将数字显示在屏幕中央。如果单位数超过200个，编辑器压力会显著增加[^1]</p></li><li><p><strong>系统配置优化</strong> — 游戏运行时，按Ctrl+Alt+Delete打开任务管理器，找到war3.exe，将进程优先级设置为&quot;高&quot;可以一定程度改善卡顿[^4]</p></li><li><p><strong>善用注释</strong> — 在复杂触发器的每个关键步骤前添加中文注释（如&quot;// 检测单位死亡&quot;），这不仅帮助他人理解，也方便自己日后调试</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：调试时要<strong>一次只改一个地方</strong>，然后立即测试效果。很多人犯的错误是同时修改五六处，结果不知道哪项改动真正起作用了。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能够：</p><ul><li>✅ 使用调试信息定位卡顿的触发器</li><li>✅ 用禁用/启用法快速排查性能瓶颈</li><li>✅ 掌握基本的计时器测量技巧</li><li>✅ 了解发布前清理调试代码的重要性</li></ul><p>掌握这些工具后，你就已经具备了独立分析和解决地图卡顿问题的能力。接下来可以继续学习触发器编写规范，从源头减少性能问题的发生。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/threads/how-to-improve-the-performance-reduce-lags-of-a-map-with-many-units-fighting-and-spawned.332106/" target="_blank" rel="noreferrer">[General] - How to improve the performance/reduce lags of a map with many units fighting and spawned</a> — accessed 2026-05-21 [^2]: <a href="https://www.hiveworkshop.com/threads/general-questions-about-trigger-optimizing-and-performance.346180/" target="_blank" rel="noreferrer">General Questions about Trigger Optimizing and Performance</a> — accessed 2026-05-21 [^3]: <a href="https://www.reddit.com/r/warcraft3/comments/o45ryw/how_to_stop_map_lag/" target="_blank" rel="noreferrer">How to stop map lag : r/warcraft3</a> — accessed 2026-05-21 [^4]: <a href="https://www.thehelper.net/threads/increasing-warcraft-iii-performance-vista.94017/" target="_blank" rel="noreferrer">Tutorial - Increasing Warcraft III Performance - Vista</a> — accessed 2026-05-21</p>',84)])])}const c=t(l,[["render",i]]);export{q as __pageData,c as default};
